    for (int num : numbers) {
        if (num % 2 == 0) {
            evenNumbers.push_back(num);
        } else {
            oddNumbers.push_back(num);
        }
    }

    // Sort even and odd numbers
    sort(evenNumbers.begin(), evenNumbers.end());
    sort(oddNumbers.begin(), oddNumbers.end());

    // Output the results
